  var mx=parseInt(D.stamina_max,10)||100;
  var pct=Math.max(0,Math.min(100,Math.round(st/mx*100)));
  var low=pct<=10, mid=(pct<=40&&pct>10);
  var cls=low?'low':(mid?'mid':'');

  g('shtag').textContent=L.tag;
  g('shname').textContent=name;
  g('shpct').textContent=pct+'%';

  var h='';
  if(form) h+='<div class="tform">'+form+'</div>';
  h+='<div class="sub">'+L.sub+'</div>';
  h+='<div class="stam"><div class="stam-top"><div class="stam-k">'+L.stam+'</div><div class="stam-v">'+pct+'%</div></div>'+
